import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { JukeboxToastParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/JukeboxToastParser';

export class JukeboxToastEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, JukeboxToastParser);
    }

    public getParser(): JukeboxToastParser {
        return this.parser as JukeboxToastParser;
    }
}
